const checkpoints = [];
const quotes = JSON.parse(localStorage.getItem('quoterequests') || '[]');
const timeslots = JSON.parse(localStorage.getItem('movetimeslots') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
let baselineMs = null;
if (metadata && metadata.baselineDate) {
  baselineMs = Date.parse(metadata.baselineDate + 'T00:00:00Z');
}
// Find the most recent qualifying quote submitted after baseline
let candidate = null;
let latestMs = -1;
for (let i = 0; i < quotes.length; i++) {
  const q = quotes[i];
  const createdMs = Date.parse(q.created_at || q.move_date || '');
  if (baselineMs && (!createdMs || createdMs < baselineMs)) continue;
  if (q.home_size !== '2_bedroom_apartment') continue;
  if (q.move_scope !== 'local') continue;
  if (q.service_type && q.service_type !== 'standard_move') continue;
  if (!q.move_date || q.move_date.substring(0,10) !== '2026-06-15') continue;
  if (q.status !== 'submitted') continue;
  if (!isNaN(createdMs) && createdMs > latestMs) {
    latestMs = createdMs;
    candidate = q;
  }
}
// Compute the lowest-hourly slot on 2026-06-15 for local standard moves at or below $150/hr
const slotsForDay = timeslots.filter(function (s) {
  if (s.move_scope !== 'local') return false;
  if (s.service_type !== 'standard_move') return false;
  const dateStr = typeof s.date === 'string' ? s.date.substring(0,10) : '';
  if (dateStr !== '2026-06-15') return false;
  if (typeof s.hourly_rate !== 'number') return false;
  if (s.hourly_rate > 150) return false;
  return true;
});
let minSlot = null;
for (let i = 0; i < slotsForDay.length; i++) {
  const s = slotsForDay[i];
  if (!minSlot || s.hourly_rate < minSlot.hourly_rate) {
    minSlot = s;
  }
}
// CP1 (0.4): Quote selects the lowest qualifying slot at or under $150/hr
const cp1Passed = !!(candidate && minSlot && candidate.preferred_timeslot_id === minSlot.id && typeof candidate.selected_hourly_rate === 'number' && candidate.selected_hourly_rate === minSlot.hourly_rate);
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.3): Quote is for a local 2-bedroom apartment standard move on 2026-06-15
const cp2Passed = !!(candidate && candidate.home_size === '2_bedroom_apartment' && candidate.move_scope === 'local' && (!candidate.service_type || candidate.service_type === 'standard_move') && candidate.move_date && candidate.move_date.substring(0,10) === '2026-06-15');
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3 (0.3): Contact details are provided (name, phone, email)
const cp3Passed = !!(candidate && candidate.contact_name && candidate.contact_phone && candidate.contact_email);
checkpoints.push({ passed: cp3Passed, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const bookings = JSON.parse(localStorage.getItem('movebookings') || '[]');
const timeslots = JSON.parse(localStorage.getItem('movetimeslots') || '[]');
const addons = JSON.parse(localStorage.getItem('addons') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
let baselineMs = null;
if (metadata && metadata.baselineDate) {
  baselineMs = Date.parse(metadata.baselineDate + 'T00:00:00Z');
}
// Filter to bookings created after baseline
const recentBookings = bookings.filter(b => {
  const createdMs = Date.parse(b.created_at || '');
  if (baselineMs && (!createdMs || createdMs < baselineMs)) return false;
  return true;
});
// Bookings that match the full-service 3-mover local timeslot and pricing requirements
const timeslotQualified = recentBookings.filter(b => {
  if (b.service_type !== 'full_service_move') return false;
  if (b.move_scope !== 'local') return false;
  if (b.crew_size !== 3) return false;
  if (b.includes_truck !== true) return false;
  if (!b.timeslot_id) return false;
  const slot = timeslots.find(s => s.id === b.timeslot_id);
  if (!slot) return false;
  const dateStr = typeof slot.date === 'string' ? slot.date.substring(0,10) : '';
  if (dateStr < '2026-06-15' || dateStr > '2026-06-21') return false; // third week of June window
  if (slot.service_type !== 'full_service_move') return false;
  if (slot.move_scope !== 'local') return false;
  if (slot.crew_size !== 3) return false;
  if (typeof slot.estimated_total !== 'number' || slot.estimated_total >= 900) return false;
  return true;
});
// CP1 (0.4): At least one booking meets the 3-mover local full-service, third-week-of-June, < $900 estimate criteria
const cp1Passed = timeslotQualified.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.3): Among those, at least one is a 2-bedroom apartment/condo with booking completed (status not draft and contact info filled)
const cp2Passed = timeslotQualified.some(b => {
  if (b.property_type !== 'apartment_condo') return false;
  if (b.home_size !== '2_bedroom_apartment') return false;
  if (!b.booking_status || b.booking_status === 'draft') return false;
  if (!b.contact_name || !b.contact_phone || !b.contact_email) return false;
  return true;
});
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3 (0.3): Among the timeslot-qualified bookings, at least one includes packing add-ons but no storage add-ons
const cp3Passed = timeslotQualified.some(b => {
  if (!Array.isArray(b.add_on_ids)) return false;
  const selectedAddOns = b.add_on_ids.map(id => addons.find(a => a.id === id)).filter(a => !!a);
  const hasPacking = selectedAddOns.some(a => a.is_packing === true);
  const hasStorage = selectedAddOns.some(a => a.is_storage === true);
  return hasPacking && !hasStorage;
});
checkpoints.push({ passed: cp3Passed, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const filterParams = JSON.parse(localStorage.getItem('task3_filterParams') || 'null');
const comparisonListId = localStorage.getItem('currentComparisonListId');
const lists = JSON.parse(localStorage.getItem('packagecomparisonlists') || '[]');
