if (comparisonListId) {
  list = lists.find(l => l.id === comparisonListId) || null;
}
// CP1 (0.4): User used a filter consistent with local packages, <= $140/hr, rating >= 4.0, >= 20 reviews, sorted by rating desc
let cp1Passed = false;
if (filterParams) {
  let tsOk = true;
  if (baselineMs && filterParams.timestamp) {
    const tsMs = Date.parse(filterParams.timestamp);
    if (!tsMs || tsMs < baselineMs) tsOk = false;
  }
  const scopeOk = filterParams.move_scope === 'local';
  const rateMaxOk = typeof filterParams.hourly_rate_max === 'number' && filterParams.hourly_rate_max <= 140;
  const ratingOk = typeof filterParams.rating_min === 'number' && filterParams.rating_min >= 4.0;
  const reviewsOk = typeof filterParams.min_review_count === 'number' && filterParams.min_review_count >= 20;
  const sortOk = filterParams.sort_by === 'rating_desc';
  cp1Passed = tsOk && scopeOk && rateMaxOk && ratingOk && reviewsOk && sortOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// Determine the top qualifying package dynamically
const qualifyingPkgs = packages.filter(p => {
  if (p.is_active === false) return false;
  if (p.move_scope !== 'local') return false;
  if (typeof p.base_hourly_rate !== 'number' || p.base_hourly_rate > 140) return false;
  const rating = typeof p.rating === 'number' ? p.rating : 0;
  if (rating < 4.0) return false;
  const rc = typeof p.review_count === 'number' ? p.review_count : 0;
  if (rc < 20) return false;
  return true;
});
qualifyingPkgs.sort((a, b) => {
  const ra = typeof a.rating === 'number' ? a.rating : 0;
  const rb = typeof b.rating === 'number' ? b.rating : 0;
  if (rb !== ra) return rb - ra;
  // tie-breaker: lower hourly rate first
  const ha = typeof a.base_hourly_rate === 'number' ? a.base_hourly_rate : 0;
  const hb = typeof b.base_hourly_rate === 'number' ? b.base_hourly_rate : 0;
  return ha - hb;
});
const top = qualifyingPkgs[0];
// CP2 (0.6): The comparison list contains the top qualifying package
let cp2Passed = false;
if (top && list && Array.isArray(list.package_ids)) {
  cp2Passed = list.package_ids.indexOf(top.id) !== -1;
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const bookings = JSON.parse(localStorage.getItem('movebookings') || '[]');
const timeslots = JSON.parse(localStorage.getItem('movetimeslots') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
let baselineMs = null;
if (metadata && metadata.baselineDate) {
  baselineMs = Date.parse(metadata.baselineDate + 'T00:00:00Z');
}
const recentBookings = bookings.filter(b => {
  const createdMs = Date.parse(b.created_at || '');
  if (baselineMs && (!createdMs || createdMs < baselineMs)) return false;
  return true;
});
// Studio local standard bookings after baseline
const studioBookings = recentBookings.filter(b => {
  if (b.service_type !== 'standard_move') return false;
  if (b.move_scope !== 'local') return false;
  if (b.home_size !== 'studio') return false;
  if (b.property_type !== 'apartment_condo') return false;
  return true;
});
function slotFor(b) {
  if (!b.timeslot_id) return null;
  return timeslots.find(s => s.id === b.timeslot_id) || null;
}
function isEarlyJuneSlot(slot) {
  if (!slot) return false;
  const dateStr = typeof slot.date === 'string' ? slot.date.substring(0,10) : '';
  if (dateStr < '2026-06-01' || dateStr > '2026-06-15') return false;
  const start = slot.start_time || '';
  return start >= '09:00' && start < '12:00';
}
function isEarliestMorningSlot(slot) {
  if (!slot) return false;
  const dateStr = typeof slot.date === 'string' ? slot.date.substring(0,10) : '';
  if (!dateStr) return false;
  const sameDaySlots = timeslots.filter(s => {
    const d = typeof s.date === 'string' ? s.date.substring(0,10) : '';
    if (d !== dateStr) return false;
    const st = s.start_time || '';
    return st >= '09:00' && st < '12:00';
  });
  if (sameDaySlots.length === 0) return false;
  let earliest = sameDaySlots[0];
  for (let i = 1; i < sameDaySlots.length; i++) {
    if (sameDaySlots[i].start_time < earliest.start_time) {
      earliest = sameDaySlots[i];
    }
  }
  return earliest.id === slot.id;
}
// CP1 (0.4): At least one studio booking uses an early-June slot whose start is 9–12 and is the earliest such slot that day
const cp1Passed = studioBookings.some(b => {
  const slot = slotFor(b);
  return isEarlyJuneSlot(slot) && isEarliestMorningSlot(slot);
});
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.3): Among those bookings, at least one has booking completed with contact details
const cp2Passed = studioBookings.some(b => {
  const slot = slotFor(b);
  if (!isEarlyJuneSlot(slot) || !isEarliestMorningSlot(slot)) return false;
  if (!b.booking_status || b.booking_status === 'draft') return false;
  if (!b.contact_name || !b.contact_phone || !b.contact_email) return false;
  return true;
});
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3 (0.3): The selected booking uses a 2-mover crew with a truck for the studio move
const cp3Passed = studioBookings.some(b => {
  const slot = slotFor(b);
  if (!isEarlyJuneSlot(slot) || !isEarliestMorningSlot(slot)) return false;
  if (b.crew_size !== 2) return false;
  if (b.includes_truck !== true) return false;
  return true;
});
checkpoints.push({ passed: cp3Passed, weight: 0.3 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const estimates = JSON.parse(localStorage.getItem('moveestimates') || '[]');
const estimateItems = JSON.parse(localStorage.getItem('estimateitems') || '[]');
const inventory = JSON.parse(localStorage.getItem('inventoryitems') || '[]');
const bookings = JSON.parse(localStorage.getItem('movebookings') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
let baselineMs = null;
if (metadata && metadata.baselineDate) {
  baselineMs = Date.parse(metadata.baselineDate + 'T00:00:00Z');
}
const movingBoxItem = inventory.find(it => it.code === 'moving_box');
function boxesForEstimate(id) {
  if (!movingBoxItem) return 0;
  return estimateItems.filter(ei => ei.estimate_id === id && ei.inventory_item_id === movingBoxItem.id)
    .reduce((sum, ei) => sum + (Number(ei.quantity) || 0), 0);
}
// 1BR estimates created after baseline
const recentEstimates = estimates.filter(e => {
  const createdMs = Date.parse(e.created_at || '');
  if (baselineMs && (!createdMs || createdMs < baselineMs)) return false;
  return e.home_size === '1_bedroom';
});
let larger = null;
let smaller = null;
// Find a pair of estimates where box count decreases and the later one is <= $500 total
for (let i = 0; i < recentEstimates.length; i++) {
  for (let j = 0; j < recentEstimates.length; j++) {
    if (i === j) continue;
    const e1 = recentEstimates[i];
    const e2 = recentEstimates[j];
    const t1 = Date.parse(e1.created_at || '');
    const t2 = Date.parse(e2.created_at || '');
    if (!t1 || !t2 || t2 < t1) continue; // e2 should be recalculation after e1
    const b1 = boxesForEstimate(e1.id);
    const b2 = boxesForEstimate(e2.id);
    if (b1 >= 30 && b2 <= 10 && b2 < b1 && typeof e2.total === 'number' && e2.total <= 500) {
      larger = e1;
      smaller = e2;
      break;
    }
  }
  if (larger && smaller) break;
}
// CP1 (0.4): Found such a pair of 1BR estimates with reduced boxes bringing total under $500
const cp1Passed = !!(larger && smaller);
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.6): There is a booking started from the adjusted estimate, under $500, for a 1-bedroom move
let cp2Passed = false;
if (smaller) {
  const bookingFromEstimate = bookings.find(b => {
    const createdMs = Date.parse(b.created_at || '');
    if (baselineMs && (!createdMs || createdMs < baselineMs)) return false;
    if (b.source_type !== 'estimator') return false;
    if (b.estimate_id !== smaller.id) return false;
    if (b.home_size !== '1_bedroom') return false;
    if (typeof b.total_estimated !== 'number' || b.total_estimated > 500) return false;
    return true;
  });
  cp2Passed = !!bookingFromEstimate;
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpts = [];
