const loadingOption = laborOptions.find(lo => lo.code === 'loading_unloading_only');
const laborBookings = recentBookings.filter(b => {
  if (b.service_type !== 'labor_only') return false;
  if (b.move_scope !== 'local') return false;
  if (b.crew_size !== 2) return false;
  if (b.includes_truck !== false) return false;
