});
// CP1 (0.4): There is a labor-only booking with 2 movers, 2-hour duration, <= $120/hr, and loading/unloading-only option selected
const cp1Passed = laborBookings.some(b => {
  if (typeof b.estimated_hours !== 'number' || b.estimated_hours !== 2) return false;
  if (typeof b.base_hourly_rate !== 'number' || b.base_hourly_rate > 120) return false;
  if (!loadingOption || b.labor_service_option_id !== loadingOption.id) return false;
  return true;
});
checkpts.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.3): Among those, at least one booking is completed with contact information
const cp2Passed = laborBookings.some(b => {
  if (typeof b.estimated_hours !== 'number' || b.estimated_hours !== 2) return false;
  if (typeof b.base_hourly_rate !== 'number' || b.base_hourly_rate > 120) return false;
  if (!loadingOption || b.labor_service_option_id !== loadingOption.id) return false;
  if (!b.booking_status || b.booking_status === 'draft') return false;
  if (!b.contact_name || !b.contact_phone || !b.contact_email) return false;
  return true;
});
checkpts.push({ passed: cp2Passed, weight: 0.3 });
// CP3 (0.3): The selected booking uses a time slot within roughly the next week from baseline
let cp3Passed = false;
