  cp3Passed = laborBookings.some(b => {
    if (!b.timeslot_id) return false;
    const slot = timeslots.find(s => s.id === b.timeslot_id);
    if (!slot || !slot.date) return false;
    const slotMs = Date.parse(slot.date);
    if (!slotMs) return false;
    return slotMs >= baselineMs && slotMs <= baselineMs + oneWeekMs;
